import axios from "axios";
import React, { useEffect, useState } from "react";
import { Link, useNavigate, useParams } from "react-router-dom";

function ViewMerch() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [merch, setMerch] = useState(null);
  const [error, setError] = useState("");
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    price: "",
    description: "",
    stock: "",
    category: "",
  });

  useEffect(() => {
    axios
      .get(`http://localhost:4000/merch/${id}`)
      .then((res) => {
        const merchData = res.data.merch;
        setMerch(merchData);
        setFormData({
          name: merchData.name || "",
          price: merchData.price || "",
          description: merchData.description || "",
          stock: merchData.stock || "",
          category: merchData.category || "",
        });
      })
      .catch(() => setError("Unable to load merchandise details."));
  }, [id]);

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleUpdate = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.put(`http://localhost:4000/merch/${id}`, formData);
      setMerch(res.data.merch);
      setIsEditing(false);
    } catch {
      setError("Unable to update merchandise.");
    }
  };

  const handleDelete = async () => {
    const isConfirmed = window.confirm("Are you sure you want to delete this product?");

    if (!isConfirmed) {
      return;
    }

    try {
      await axios.delete(`http://localhost:4000/merch/${id}`);
      navigate("/merch");
    } catch {
      setError("Unable to delete merchandise.");
    }
  };

  if (error) {
    return <p>{error}</p>;
  }

  if (!merch) {
    return <p>Loading merchandise details...</p>;
  }

  const imageUrl = merch.image ? `http://localhost:4000${merch.image}` : "";

  if (isEditing) {
    return (
      <form onSubmit={handleUpdate}>
        <h1>Edit {merch.name}</h1>
        <input
          type="text"
          name="name"
          value={formData.name}
          onChange={handleChange}
          placeholder="Name"
        />
        <input
          type="number"
          name="price"
          value={formData.price}
          onChange={handleChange}
          placeholder="Price"
        />
        <textarea
          name="description"
          value={formData.description}
          onChange={handleChange}
          placeholder="Description"
        />
        <input
          type="number"
          name="stock"
          value={formData.stock}
          onChange={handleChange}
          placeholder="Stock"
        />
        <input
          type="text"
          name="category"
          value={formData.category}
          onChange={handleChange}
          placeholder="Category"
        />
        <button type="submit">Save Changes</button>
        <button type="button" onClick={() => setIsEditing(false)}>
          Cancel
        </button>
      </form>
    );
  }

  return (
    <div>
      <h1>{merch.name}</h1>
      {imageUrl && <img src={imageUrl} alt={merch.name} width="300" />}
      <p>Price: LKR.{merch.price}</p>
      <p>Description: {merch.description}</p>
      <p>Stock: {merch.stock}</p>
      <p>Category: {merch.category}</p>
      <button onClick={() => setIsEditing(true)}>Edit</button>
      <button onClick={handleDelete}>Delete</button>
      <Link to="/merch">
        <button>Back to Merch List</button>
      </Link>
    </div>
  );
}

export default ViewMerch;
